    blueprintArea: "ISC-I",
    topic: "Enterprise Systems",
    subtopic: "General Ledger System Controls",
    difficulty: "medium",
    skillLevel: "Application",
    question: "Key controls in a General Ledger (GL) system include:",
    options: ["Only password protection","Automated journal entry validation (balanced debits/credits), restricted access to the chart of accounts, period-end closing procedures, trial balance reconciliation, and management review of manual journal entries","Printing all journal entries daily","Only quarterly reviews"],
