    id: "isc-gen-1081",
    courseId: "cpa",
    section: "ISC",
    blueprintArea: "ISC-I",
    topic: "System development life cycle (SDLC)",
    subtopic: "Security Considerations in SDLC",
    difficulty: "medium",
